const { execSync } = require('child_process');
const fs = require('fs');
const path = require('path');

const vaultPath = 'E:\\数字\\vault\\数字分身';
const speDir = 'E:\\数字\\.specstory\\history';
const exportDir = path.join(vaultPath, '对话导出');
const scriptPath = path.join(vaultPath, '..', '..', 'N8N', 'scripts', 'specstory_clean.py');

if (!fs.existsSync(exportDir)) fs.mkdirSync(exportDir, { recursive: true });

// 读取对话导出目录所有md文件
let allExportFiles = [];
try { allExportFiles = fs.readdirSync(exportDir).filter(f => f.endsWith('.md')); } catch(e) {}

// 把文件名标准化为「不带秒数」的版本，用于去重比对
// 2026-03-17_06-00-54Z-xxx.md → 2026-03-17_06-00Z-xxx.md
function normalizeSpeName(name) {
  return name.replace(/(\d{4}-\d{2}-\d{2}_\d{2}-\d{2})-\d{2}Z/, '$1Z');
}

// 构建已处理的SpecStory原始文件名集合（防增殖核心逻辑）
// 统一用「不带秒数」版本存储，避免带秒/不带秒两种格式导致的重复
// 跨批次去重：同一SPE文件无论被哪个批次处理过，都视为已处理
let processedSpeNames = new Set();
for (const ef of allExportFiles) {
  // 情况1：无前缀的同名文件（刚清洗还没被重命名节点处理）
  if (!ef.startsWith('[')) {
    processedSpeNames.add(normalizeSpeName(ef));
  }
  // 情况2：已加[导出]前缀 → 从文件名里提取SPE原始文件名
  // 兼容带秒（_HH-mm-ssZ）和不带秒（_HH-mmZ）两种格式
  // [导出] 2026-03-18-2123-2026-03-11_14-50-19Z-xxx.md → 2026-03-11_14-50Z-xxx.md
  // [导出] 2026-03-18-2123-2026-03-11_14-50Z-xxx.md   → 2026-03-11_14-50Z-xxx.md
  // 注意：批次时间戳（YYYY-MM-DD-HHMM）不同但SPE核心名相同 = 同一对话，跳过
  const m = ef.match(/^\[导出\]\s*\d{4}-\d{2}-\d{2}-\d{4}-(\d{4}-\d{2}-\d{2}_\d{2}-\d{2}(?:-\d{2})?Z-.+\.md)$/);
  if (m) {
    processedSpeNames.add(normalizeSpeName(m[1]));
  }
}

const speFiles = fs.readdirSync(speDir).filter(f => f.endsWith('.md'));
let cleaned = 0;
let skipped = 0;
let errors = [];

// 额外扫描：待确认+可能重复+对话删除目录，提取SPE原始文件名加入已处理集合
// 防止同一对话的 File A / File B 因标题slug不同而漏过去重
const extraDirs = ['待确认', '可能重复', '对话删除'];
for (const dirName of extraDirs) {
  const dirPath = path.join(vaultPath, dirName);
  let dirFiles = [];
  try { dirFiles = fs.readdirSync(dirPath).filter(f => f.endsWith('.md')); } catch(e) {}
  for (const df of dirFiles) {
    // 去掉 [待确认] / [可能重复] 等前缀
    const coreName = df.replace(/^\[.*?\]\s*/, '');
    processedSpeNames.add(normalizeSpeName(coreName));
  }
}

// 源头过滤：只处理 File A（不带秒），跳过 File B（带秒）
const fileBPattern = /^\d{4}-\d{2}-\d{2}_\d{2}-\d{2}-\d{2}Z/;
const filteredSpeFiles = speFiles.filter(f => !fileBPattern.test(f));
let filteredOut = speFiles.length - filteredSpeFiles.length;

for (const f of filteredSpeFiles) {
  // 用normalize后的名字比对（兼容带秒/不带秒两种格式）
  if (processedSpeNames.has(normalizeSpeName(f))) { skipped++; continue; }

  const inputPath = path.join(speDir, f);
  const outputPath = path.join(exportDir, f);

  try {
    execSync('python "' + scriptPath + '" "' + inputPath + '" "' + outputPath + '"', {
      encoding: 'utf-8',
      timeout: 30000
    });
    cleaned++;
  } catch(e) {
    errors.push(f + ': ' + String(e).slice(0, 100));
  }
}

return { json: { cleaned: cleaned, skipped: skipped, filteredFileB: filteredOut, errors: errors, processedCount: processedSpeNames.size } };

// 改动2：重命名导出文件（原节点不变，加[导出]前缀）
const fs = require('fs');
const path = require('path');
const vaultPath = 'E:\\数字\\vault\\数字分身';
const exportDir = path.join(vaultPath, '对话导出');
if (!fs.existsSync(exportDir)) { return { json: { renamed: 0 } }; }
const files = fs.readdirSync(exportDir);
let renamed = 0;
for (const f of files) {
  if (!f.endsWith('.md') || f.startsWith('[导出]')) continue;
  const filePath = path.join(exportDir, f);
  const stat = fs.statSync(filePath);
  const mt = stat.mtime;
  const y = mt.getFullYear();
  const mo = String(mt.getMonth() + 1).padStart(2, '0');
  const d = String(mt.getDate()).padStart(2, '0');
  const h = String(mt.getHours()).padStart(2, '0');
  const mi = String(mt.getMinutes()).padStart(2, '0');
  const dateStr = y + '-' + mo + '-' + d + '-' + h + mi;
  const newName = '[导出] ' + dateStr + '-' + f;
  const newPath = path.join(exportDir, newName);
  if (fs.existsSync(newPath)) continue;
  fs.renameSync(filePath, newPath);
  renamed++;
}
return { json: { renamed: renamed } };

const fs = require('fs');
const path = require('path');
const vaultPath = 'E:\\数字\\vault\\数字分身';
const dictPath = path.join(vaultPath, '全局实体字典.md');
let content = '';
try { content = fs.readFileSync(dictPath, 'utf-8'); } catch(e) { content = ''; }
