const fs = require('fs');
const path = require('path');
const vaultPath = 'E:\\数字\\vault\\数字分身';
const exportDir = path.join(vaultPath, '对话导出');
let files = [];
try { files = fs.readdirSync(exportDir); } catch(e) { return []; }
const result = [];
