const fs = require('fs');
const path = require('path');
const vaultPath = 'E:\\数字\\vault\\数字分身';
const pendingDir = path.join(vaultPath, '待确认');
const deletedDir = path.join(vaultPath, '对话删除');
const maybeDupDir = path.join(vaultPath, '可能重复');
if (!fs.existsSync(pendingDir)) { fs.mkdirSync(pendingDir, { recursive: true }); }
const result = [];
for (const dir of [pendingDir, deletedDir, maybeDupDir]) {
  let files = [];
  try { files = fs.readdirSync(dir); } catch(e) {}
  for (var i = 0; i < files.length; i++) {
    var f = files[i];
    if (!f.endsWith('.md')) continue;
    result.push({ json: { name: f, type: 'file' } });
  }
}
if (result.length === 0) { result.push({ json: { name: '', type: 'empty' } }); }
return result;

const fs = require('fs');
const path = require('path');
const vaultPath = 'E:\\数字\\vault\\数字分身';
const archiveDir = path.join(vaultPath, '对话存档');
let files = [];
try { files = fs.readdirSync(archiveDir).filter(f => f.endsWith('.md')); } catch(e) {}
const result = [];
for (const f of files) {
  const filePath = path.join(archiveDir, f);
  let lines = [];
  try {
    const content = fs.readFileSync(filePath, 'utf-8');
    lines = content.split(/\r?\n/).slice(0, 15);
  } catch(e) { continue; }
  let originalFile = '';
  for (const line of lines) {
    const m = line.match(/^original_file:\s*"?([^"\n]+)"?/);
    if (m) { originalFile = m[1].trim(); break; }
  }
  if (!originalFile) continue;
  const coreName = originalFile.replace(/^\[.*?\]\s*/, '');
  result.push({ json: { name: coreName, type: 'archived' } });
}
return result;

// 三目录联合排除：待确认 + 对话删除 + 对话存档
var excludeNames = {};
// 来源1：列出待确认（待确认/ + 对话删除/）
var pendingItems = $('列出待确认').all();
for (var i = 0; i < pendingItems.length; i++) {
  var pn = String(pendingItems[i].json.name || '');
  if (pn.endsWith('.md')) {
    excludeNames[pn.replace(/^\[.*?\]\s*/, '')] = true;
  }
}
// 来源2：列出对话存档（从original_file提取coreName）
var archivedItems = $input.all();
for (var j = 0; j < archivedItems.length; j++) {
  var an = String(archivedItems[j].json.name || '');
  if (an) excludeNames[an] = true;
}
// 过滤对话导出
var exportItems = $('列出对话导出').all();
if (!exportItems || exportItems.length === 0) { return []; }
var result = [];
for (var k = 0; k < exportItems.length; k++) {
  var item = exportItems[k];
  var name = String(item.json.name || '');
  var type = String(item.json.type || '');
  if (type !== 'file' || !name.endsWith('.md')) continue;
  var coreName = name.replace(/^\[.*?\]\s*/, '').replace(/^\d{4}-\d{2}-\d{2}-\d{4}-/, '');
  if (excludeNames[coreName]) continue;
  result.push({ json: { name: name, path: String(item.json.path || ''), sha: String(item.json.sha || '') } });
}
return result;

if (!$json || !$json.path) { return []; }
const fs = require('fs');
const path = require('path');
const vaultPath = 'E:\\数字\\vault\\数字分身';
const filePath = path.join(vaultPath, $json.path);
let content = '';
let fileName = path.basename(filePath);
try { content = fs.readFileSync(filePath, 'utf-8'); } catch(e) {
  return { json: { _skip: true, _error: String(e), name: fileName, content: '' } };
}
return { json: { content: content, name: fileName, path: $json.path } };

// 改动3：清洗组装节点瘦身
// Python脚本已做：tool-use删除、thinking删除、AI回复合并、角色行改写、HTML注释删除
// 本节点只做：元信息提取、字典替换、角色改中文、frontmatter生成、组装输出
if (!$json || !$json.content || $json._skip) { return []; }

var raw = $json.content || '';
var fileName = $json.name || '';
if (!raw || !fileName) { return []; }

// === 2. 提取元信息 ===
var dateStr = new Date().toISOString().slice(0, 10);
var dateFromName = fileName.match(/\[导出\] (\d{4})-(\d{2})-(\d{2})/);
if (dateFromName) {
  dateStr = dateFromName[1] + '-' + dateFromName[2] + '-' + dateFromName[3];
} else {
  var dateFromContent = raw.match(/Cleaned from SpecStory on (\d{4}-\d{2}-\d{2})/);
  if (dateFromContent) { dateStr = dateFromContent[1]; }
}

// 模型信息：从清洗后的 **Cursor (model xxx, mode xxx)** 提取
var modelsSet = new Set();
var modelMatches = raw.matchAll(/\*\*Cursor \(model ([^,]+),/g);
for (const m of modelMatches) { modelsSet.add(m[1].trim()); }
var modelsList = modelsSet.size > 0 ? Array.from(modelsSet) : ['Cursor'];

// 用户轮次
var userTurns = (raw.match(/\*\*User\*\*/g) || []).length;

// 标题
var title = fileName.replace(/\.md$/, '').replace(/^\[.*?\]\s*/, '');
var titleMatch = raw.match(/^# (.+?)(?:\s*\(.+?\))?\s*$/m);
if (titleMatch) title = titleMatch[1].trim();

// === 3. 获取并解析实体字典 ===
var dictContent = '';
try { dictContent = $('读取实体字典').first().json.content || ''; } catch(e) {}

var entityMap = {};
var dictLines = dictContent.split(/\r?\n/);
for (var i = 0; i < dictLines.length; i++) {
  var em = dictLines[i].match(/^\|\s*(.+?)\s*\|\s*(.+?)\s*\|/);
  if (!em) continue;
  if (em[1].indexOf('---') !== -1 || em[1].indexOf('别名') !== -1 || em[1].indexOf('可能的叫法') !== -1 || em[1].indexOf('日期') !== -1 || em[1].indexOf('原始表达') !== -1 || em[1].indexOf('常见错误') !== -1) continue;
  var standard = em[2].trim();
  if (!standard || standard === '标准实体' || standard === '标准表达' || standard === '正确写法' || standard === '更新内容') continue;
  var aliasParts = em[1].split(/[,，、\/]/);
  for (var j = 0; j < aliasParts.length; j++) {
    var alias = aliasParts[j].trim();
    if (alias && alias !== standard) entityMap[alias] = standard;
  }
}
var sortedAliases = Object.keys(entityMap).sort(function(a, b) { return b.length - a.length; });

// === 4. 分离 YAML frontmatter 和正文 ===
var bodyText = raw;
if (raw.indexOf('---') === 0) {
  var fmEnd = raw.indexOf('\n---', 3);
  if (fmEnd !== -1) { bodyText = raw.substring(fmEnd + 4); }
}

// === 5. 字典替换 ===
var replacedCount = 0;
for (var k = 0; k < sortedAliases.length; k++) {
  var alias = sortedAliases[k];
  var stdName = entityMap[alias];
  var esc = alias.replace(/[.*+?^${}()|[\]\\]/g, '\\$&');
  var re = new RegExp(esc, 'g');
  bodyText = bodyText.replace(re, function(match) {
    replacedCount++;
    return '~~' + match + '~~==' + stdName + '==';
  });
}

// === 6. 格式转换：**User** / **Cursor (...)** → 中文标题 ===
var c = bodyText;
c = c.replace(/\*\*User\*\*/g, '\n### 👤 用户');
c = c.replace(/\*\*Cursor \(model ([^,]+), mode ([^)]+)\)\*\*/g, '\n### 🤖 Cursor ($1)');
c = c.replace(/\*\*Cursor \([^)]+\)\*\*/g, '\n### 🤖 Cursor');
c = c.replace(/\*\*Cursor\*\*/g, '\n### 🤖 Cursor');

// 清理连续空行
c = c.replace(/\n{4,}/g, '\n\n');
c = c.trim();

// === 7. 生成 YAML 头 + 组装输出（改动4：source改为SpecStory/Cleaned）===
// strip导出时间戳，保留SPE原始时间格式
// [导出] 2026-03-18-2206-2026-03-11_14-50Z-xxx.md → [待确认] 2026-03-11_14-50Z-xxx.md
var coreName = fileName.replace(/^\[.*?\]\s*/, '');
var stripExportTime = coreName.replace(/^\d{4}-\d{2}-\d{2}-\d{4}-/, '');
var outputFileName = '[待确认] ' + stripExportTime;
var yaml = '---\ntype: 待确认\nsource: SpecStory/Cleaned\ndate: ' + dateStr +
  '\nmodels: [' + modelsList.join(', ') + ']\nturns: ' + userTurns +
  '\ntitle: ' + JSON.stringify(title) +
  '\noriginal_file: ' + JSON.stringify(fileName) +
  '\nstatus: pending\narchive_title: ""\nreplaced_count: ' + replacedCount + '\n---';

return {
  json: {
    outputFileName: outputFileName,
    outputContent: yaml + '\n\n' + c,
    originalFileName: fileName,
    replacedCount: replacedCount,
    date: dateStr
  }
};

var items = $input.all();
var result = [];
for (var i = 0; i < items.length; i++) {
  if (!items[i].json._skip) {
    result.push(items[i]);
  }
}
return result;

if (!$json || !$json.outputFileName || !$json.outputContent) { return []; }
const fs = require('fs');
const path = require('path');
const vaultPath = 'E:\\数字\\vault\\数字分身';
const pendingDir = path.join(vaultPath, '待确认');
if (!fs.existsSync(pendingDir)) { fs.mkdirSync(pendingDir, { recursive: true }); }
const outputPath = path.join(pendingDir, $json.outputFileName);
fs.writeFileSync(outputPath, $json.outputContent, 'utf-8');
return { json: { success: true, path: outputPath, fileName: $json.outputFileName } };
